def render(rsegs, flipx=False, flipy=False, W=320):
    H=int((maxy-miny)/(maxx-minx)*W*0.5)+1
    grid=[[' ']*W for _ in range(H)]
    def put(px,py):
        gx=int((px-minx)/(maxx-minx)*(W-1))
        gy=int((py-miny)/(maxy-miny)*(H-1))
        if flipx: gx=W-1-gx
        if not flipy: gy=H-1-gy
        if 0<=gx<W and 0<=gy<H: grid[gy][gx]='#'
    for x0,y0,x1,y1 in rsegs:
        n=max(1,int(((x1-x0)**2+(y1-y0)**2)**0.5*4))
        for i in range(n+1):
            t=i/n
            put(x0+(x1-x0)*t,y0+(y1-y0)*t)
    return '\n'.join(''.join(r) for r in grid)

with open('/app/variants.txt','w') as f:
    for fx in (False,True):
        for fy in (False,True):
            f.write(f'=== flipx={fx} flipy={fy} ===\n')

