cd /app && python3 -c "
import re
from collections import Counter
x=y=z=e=0.0; in_obj=False; rel_e=True
zc=Counter()
with open('text.gcode') as f:
    for line in f:
        line=line.strip()
        if line.startswith('M486'):
            if line.startswith('M486 S0'): in_obj=True
            elif line.startswith('M486 S-1') or line.startswith('M486 S1'): in_obj=False
            continue
        if line.startswith('M82'): rel_e=False
        if line.startswith('M83'): rel_e=True
        if line.startswith('G92'):
            m=re.search(r'E(-?[\d.]+)',line);
            if m: e=float(m.group(1))
            continue
        if line[:2] in ('G1','G0'):
            de=0.0
            mz=re.search(r'Z(-?[\d.]+)',line); me=re.search(r'E(-?[\d.]+)',line)
            mx=re.search(r'X(-?[\d.]+)',line); my=re.search(r'Y(-?[\d.]+)',line)
            if mz: z=float(mz.group(1))
            if me:
                ev=float(me.group(1))
                de=ev if rel_e else ev-e
                if not rel_e: e=ev
            if in_obj and de>0.0001 and (mx or my): zc[round(z,3)]+=1
for k in sorted(zc): print(k, zc[k])
"
